// Entities & DB Types

export enum EbcTransactionPhase {
  RequestSending,
  Validation,
  Acceptance,
  Settlement,
  FinalSettlement,
  Disbursement,
  Finished,
}

export enum EbcTransactionStatus {
  Pending,
  Success,
  Failed,
}

export enum EbcProcessingStatus {
  Stall,
  Pending,
  Processing,
}

export enum EbcDisbursementStatus {
  Pending,
  Success,
}

export enum EbcMessageType {
  SendTransaction = 1,
  UpdateTransactionStatus,
}

export enum EbcMessageResponseStatus {
  FailedToGetResponse,
  ResponseReceived,
}

export enum EbcBatchType {
  UpdateTransactionStatus = 1,
}

export type EbcTransaction = {
  orgCode: number;
  transactionId: number;
  branchCode: number;
  transCode: number | null;
  clientKey: string;
  loanKey: string;
  bankKey: string;
  bankDisbAccount: string;
  clientBankId: number;
  clientBranchId: number | null;
  clientAccount: string;
  creationStamp: Date;
  creationUsername: string;
  transactionPhase: EbcTransactionPhase;
  transactionStatus: EbcTransactionStatus;
  processingStatus: EbcProcessingStatus;
  processingTimestamp: Date | null;
  transactionStatusCode: string | null;
  transactionStatusDesc: string | null;
  requestTimestamp: Date | null;
  validationStatusTimestamp: Date | null;
  acceptanceStatusTimestamp: Date | null;
  settlementStatusTimestamp: Date | null;
  finalSettlementStatusTimestamp: Date | null;
  disbStatus: EbcDisbursementStatus;
  disbStatusMessage: string | null;
  disbUsername: string | null;
  disbTimestamp: Date | null;
  batchId: number | null;
  updateUsername: string | null;
  updateStamp: Date | null;
};

export type EbcMessage = {
  orgCode: number;
  messageId: BigInt;
  transactionId: number;
  batchId: number | null;
  messageType: EbcMessageType;
  requestBody: string | null;
  requestTimestamp: Date | null;
  responseStatusCode: number | null;
  responseBody: string | null;
  responseTimestamp: Date | null;
  responseStatus: EbcMessageResponseStatus | null;
  requestStatusCode: string | null;
  requestStatusDesc: string | null;
  transactionStatusCode: string | null;
  transactionStatusDesc: string | null;
  errorMessage: string | null;
  stackTrace: string | null;
};

export type EbcBatch = {
  batchId: number;
  batchType: EbcBatchType;
  batchTimestamp: Date;
  processingStatus: EbcProcessingStatus;
  processingTimestamp: Date | null;
  completedTimestamp: Date | null;
  updateStamp: Date | null;
  errorMessage: string | null;
  stackTrace: string | null;
};

