export class SelectableList<T> {
  public items: (T & { isSelected: boolean })[];

  public get isAllSelected(): boolean {
    return this.items.every((item) => item.isSelected);
  }

  public get isSomeSelected(): boolean {
    return this.items.some((item) => item.isSelected);
  }

  public get totalCount(): number {
    return this.items.length;
  }

  public get selectedCount(): number {
    return this.items.filter((item) => item.isSelected).length;
  }

  public get selectedItems(): T[] {
    return this.items.filter((item) => item.isSelected);
  }

  constructor(items?: T[]) {
    items = items || [];
    this.items = items.map((item) => ({ ...item, isSelected: false }));
  }

  public clearItems(): void {
    this.items = [];
  }

  public setItems(items: T[]): void {
    items = items || [];
    this.items = items.map((item) => ({ ...item, isSelected: false }));
  }

  public selectAll(): void {
    this.items = this.items.map((item) => ({ ...item, isSelected: true }));
  }

  public selectItem(index: number): void {
    this.items = this.items.map((item, i) =>
      i === index ? { ...item, isSelected: true } : item
    );
  }

  public selectNone(): void {
    this.items = this.items.map((item) => ({ ...item, isSelected: false }));
  }

  public toggleSelectAll(): void {
    this.isAllSelected ? this.selectNone() : this.selectAll();
  }

  public toggleSelectItem(index: number): void {
    this.items = this.items.map((item, i) =>
      i === index ? { ...item, isSelected: !item.isSelected } : item
    );
  }
}
