import { Component, NgZone, OnInit } from "@angular/core";
import { FormBuilder, FormGroup, Validators } from "@angular/forms";
import { MohassilAuthService } from "src/app/core/services/AuthenticationServices/mohassil-auth.service";
import * as customValidators from "src/app/core/validators/custom-validators";
import { BranchBanks } from "src/app/views/Models/Banks/BranchBanks";
import { BankService } from "src/app/core/services/bank.service";
import { AlertService } from "src/app/core/services/alert.service";
import { AuthorizedTabWithPageMode } from "src/app/core/models/Auth/AuthorizedTab";
import { startOfDay, startOfMonth } from "date-fns";
import {
  EbcTransactionStatus,
  EbcTransactionViewModel,
} from "src/app/views/Models/E-Disb/EgyptianBanksCompany";
import { EDisbService } from "src/app/core/services/e-disb.service";
import { HttpErrorResponse } from "@angular/common/http";
import { SelectableList } from "src/app/core/models/SelectableList";
import { sortingService } from "src/app/core/services/sorting.service";

enum PageMode {
  SendRequest = 1,
  ViewStatus = 2,
  ManualDisburse = 3,
  ShowCompleted = 4,
}

@Component({
  selector: "app-edisb-loans",
  templateUrl: "./edisb-loans.page.html",
  styleUrls: ["./edisb-loans.page.scss"],
})
export class EdisbLoansPage implements OnInit {
  PageMode: typeof PageMode = PageMode;
  EbcTransactionStatus: typeof EbcTransactionStatus = EbcTransactionStatus;

  tabs: AuthorizedTabWithPageMode<PageMode>[] = [
    {
      tabName: "طلب التحويلات البنكية",
      windowCode: "5667",
      pageMode: PageMode.SendRequest,
    },
    {
      tabName: "حالة التحويلات البنكية",
      windowCode: "5670",
      pageMode: PageMode.ViewStatus,
    },
    {
      tabName: "التحويلات البنكية غير المصدرة",
      windowCode: "5669",
      pageMode: PageMode.ManualDisburse,
    },
    {
      tabName: "التحويلات البنكية المكتملة",
      windowCode: "5668",
      pageMode: PageMode.ShowCompleted,
    },
  ];

  sortingObject: { sortingIconClass: string; sortingIconParam: string } = {
    sortingIconClass: null,
    sortingIconParam: null,
  };

  //#region Page Objects
  showLoader: boolean = false;
  pageMode: PageMode | null = null;
  //#endregion

  //#region Data Objects
  banks: BranchBanks[] = [];
  transactionsList: SelectableList<EbcTransactionViewModel> =
    new SelectableList<EbcTransactionViewModel>();
  //#endregion

  //#region Forms
  searchFormSubmitted: boolean = false;
  searchForm: FormGroup = this.formBuilder.group({
    bankCodes: ["", Validators.required],
    loanDateFrom: [
      startOfMonth(new Date()),
      customValidators.dateTypeStringValidator({
        required: true,
      }),
    ],
    loanDateTo: [
      startOfDay(new Date()),
      customValidators.dateTypeStringValidator({
        required: true,
      }),
    ],
    transactionStatus: [EbcTransactionStatus.Pending],
  });
  //#endregion

  //#region Initialize
  constructor(
    private authService: MohassilAuthService,
    private formBuilder: FormBuilder,
    private bankService: BankService,
    private eDisbService: EDisbService,
    private alertService: AlertService,
    public sortingService: sortingService
  ) {}

  async ngOnInit() {
    this.showLoader = true;
    const userAccessRights = await this.authService.getAccessRights();
    this.tabs = this.tabs.filter((tab) =>
      userAccessRights.some(
        (accessRight) => accessRight.window_code === tab.windowCode
      )
    );
    this.pageMode = this.tabs[0]?.pageMode;

    await this.loadReferences();
    this.showLoader = false;
  }

  public sort(sortingParameter: string) {
    this.sortingService.sortByParameter(
      this.transactionsList?.items,
      sortingParameter
    );
    this.sortingObject.sortingIconClass =
      this.sortingService.sortOrder === "asc"
        ? "arrow-up-outline"
        : "arrow-down-outline";
    this.sortingObject.sortingIconParam = sortingParameter;
  }

  async changePageMode(event) {
    this.pageMode = event.detail.value;
    this.resetSearchResults();
  }

  private resetSearchResults() {
    this.transactionsList.clearItems();
    this.searchFormSubmitted = false;
    this.searchForm.patchValue({
      transactionStatus: EbcTransactionStatus.Pending,
    });
    this.resetSorting();
  }

  private resetSorting() {
    this.sortingObject = { sortingIconClass: null, sortingIconParam: null };
  }

  async loadReferences() {
    let userInfo = await this.authService.getUserInfo();
    this.banks = await this.bankService.getBranchBanks(
      Number(userInfo.branch_code)
    );
  }

  async search() {
    this.searchFormSubmitted = true;
    if (this.pageMode == PageMode.SendRequest) {
      await this.searchEbcEligibleLoans();
    } else if (this.pageMode == PageMode.ViewStatus) {
      if (
        this.searchForm.controls.transactionStatus.value ==
        EbcTransactionStatus.Pending
      ) {
        await this.searchEbcPendingTransactions();
      } else if (
        this.searchForm.controls.transactionStatus.value ==
        EbcTransactionStatus.Failed
      ) {
        await this.searchEbcFailedTransactions();
      }
    } else if (this.pageMode == PageMode.ManualDisburse) {
      await this.searchEbcUndisbursedTransactions();
    } else if (this.pageMode == PageMode.ShowCompleted) {
      await this.searchEbcCompletedTransactions();
    }

    this.resetSorting();
  }

  private async searchEbcEligibleLoans() {
    if (!this.searchForm.valid) {
      return;
    }

    this.showLoader = true;

    try {
      const transactions = await this.eDisbService.getEbcEligibleLoans(
        this.searchForm.controls.bankCodes.value,
        this.searchForm.controls.loanDateFrom.value,
        this.searchForm.controls.loanDateTo.value
      );
      this.transactionsList.setItems(transactions);
    } catch (err) {
      this.showLoader = false;
      if (err instanceof HttpErrorResponse) {
        this.alertService.showAlertError(
          JSON.stringify(err.error).replace(/\\r\\n/g, "<br />"),
          false
        );
        return;
      }
    } finally {
      this.showLoader = false;
    }
  }

  private async searchEbcPendingTransactions() {
    if (!this.searchForm.valid) {
      return;
    }

    this.showLoader = true;

    try {
      const transactions = await this.eDisbService.getEbcPendingTransactions(
        this.searchForm.controls.bankCodes.value,
        this.searchForm.controls.loanDateFrom.value,
        this.searchForm.controls.loanDateTo.value
      );
      this.transactionsList.setItems(transactions);
    } catch (err) {
      this.showLoader = false;
      if (err instanceof HttpErrorResponse) {
        this.alertService.showAlertError(
          JSON.stringify(err.error).replace(/\\r\\n/g, "<br />"),
          false
        );
        return;
      }
    } finally {
      this.showLoader = false;
    }
  }

  private async searchEbcFailedTransactions() {
    if (!this.searchForm.valid) {
      return;
    }

    this.showLoader = true;

    try {
      const transactions = await this.eDisbService.getEbcFailedTransactions(
        this.searchForm.controls.bankCodes.value,
        this.searchForm.controls.loanDateFrom.value,
        this.searchForm.controls.loanDateTo.value
      );
      this.transactionsList.setItems(transactions);
    } catch (err) {
      this.showLoader = false;
      if (err instanceof HttpErrorResponse) {
        this.alertService.showAlertError(
          JSON.stringify(err.error).replace(/\\r\\n/g, "<br />"),
          false
        );
        return;
      }
    } finally {
      this.showLoader = false;
    }
  }

  private async searchEbcUndisbursedTransactions() {
    if (!this.searchForm.valid) {
      return;
    }

    this.showLoader = true;

    try {
      const transactions =
        await this.eDisbService.getEbcUndisbursedTransactions(
          this.searchForm.controls.bankCodes.value,
          this.searchForm.controls.loanDateFrom.value,
          this.searchForm.controls.loanDateTo.value
        );
      this.transactionsList.setItems(transactions);
    } catch (err) {
      this.showLoader = false;
      if (err instanceof HttpErrorResponse) {
        this.alertService.showAlertError(
          JSON.stringify(err.error).replace(/\\r\\n/g, "<br />"),
          false
        );
        return;
      }
    } finally {
      this.showLoader = false;
    }
  }

  private async searchEbcCompletedTransactions() {
    if (!this.searchForm.valid) {
      return;
    }

    this.showLoader = true;

    try {
      const transactions = await this.eDisbService.getEbcCompletedTransactions(
        this.searchForm.controls.bankCodes.value,
        this.searchForm.controls.loanDateFrom.value,
        this.searchForm.controls.loanDateTo.value
      );
      this.transactionsList.setItems(transactions);
    } catch (err) {
      this.showLoader = false;
      if (err instanceof HttpErrorResponse) {
        this.alertService.showAlertError(
          JSON.stringify(err.error).replace(/\\r\\n/g, "<br />"),
          false
        );
        return;
      }
    } finally {
      this.showLoader = false;
    }
  }

  async sendEbcTransactions() {
    const confirmed = await this.alertService.SaveAlert(
      `هل أنت متأكد من إرسال طلب التحويل للقروض المحددة؟ (عدد القروض: ${this.transactionsList.selectedCount})`
    );

    if (!confirmed) {
      return;
    }

    this.showLoader = true;

    try {
      await this.eDisbService.sendEbcTransactions(
        this.transactionsList.selectedItems.map((i) => i.loanKey)
      );
      await this.alertService.showAlertConfirm(
        "تم إرسال طلب التحويل بنجاح",
        false
      );
      this.transactionsList.selectNone();
      await this.search();
    } catch (err) {
      this.showLoader = false;
      if (err instanceof HttpErrorResponse) {
        this.alertService.showAlertError(
          JSON.stringify(err.error).replace(/\\r\\n/g, "<br />"),
          false
        );
        return;
      }
    } finally {
      this.showLoader = false;
    }
  }

  async disburseEbcTransactions() {
    this.showLoader = true;

    try {
      await this.eDisbService.disburseEbcTransactions(
        this.transactionsList.selectedItems.map((i) => i.transactionId)
      );
      await this.alertService.showAlertConfirm(
        "تم إرسال طلب إصدار القروض بنجاح",
        false
      );
      this.transactionsList.selectNone();
      await this.search();
    } catch (err) {
      this.showLoader = false;
      if (err instanceof HttpErrorResponse) {
        this.alertService.showAlertError(
          JSON.stringify(err.error).replace(/\\r\\n/g, "<br />"),
          false
        );
        return;
      }
    } finally {
      this.showLoader = false;
    }
  }
}
